#pragma once
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>
#include <vector>
#include <ATen/ATen.h>

// Kernel function declaration
__global__ void mla_paged_decode_kernel(
    const void* __restrict__ q_nope,
    const void* __restrict__ q_pe,
    const void* __restrict__ ckv_cache,
    const void* __restrict__ kpe_cache,
    const int* __restrict__ kv_indptr,
    const int* __restrict__ kv_indices,
    void* __restrict__ output,
    float* __restrict__ lse,
    float sm_scale,
    int batch_size,
    int num_qo_heads,
    int head_dim_ckv,
    int head_dim_kpe
);

// Host function declaration
void run_mla_paged_decode(
    torch::Tensor q_nope,
    torch::Tensor q_pe,
    torch::Tensor ckv_cache,
    torch::Tensor kpe_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    torch::Tensor output,
    torch::Tensor lse,
    float sm_scale,
    int batch_size,
    int num_pages
);

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include <math.h>
#include <limits>
#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

// Constants based on specification - optimized for A800
constexpr int NUM_QO_HEADS = 16;
constexpr int HEAD_DIM_CKV = 512;
constexpr int HEAD_DIM_KPE = 64;
constexpr int PAGE_SIZE = 1;
constexpr int THREADS_PER_BLOCK = 128;  // Increased for better occupancy on A800
constexpr int THREADS_PER_HEAD = THREADS_PER_BLOCK / NUM_QO_HEADS;  // 8 threads per head
constexpr float LOG2_E = 1.4426950408889634f;  // 1/log(2)

// Shared memory buffers - optimized for A800 (164KB per SM)
// Q_nope: 16 heads * 512 dims * 4 bytes = 32KB
// Q_pe: 16 heads * 64 dims * 4 bytes = 4KB
// Kc: 512 dims * 4 bytes = 2KB
// Kp: 64 dims * 4 bytes = 0.5KB
// Total ~38.5KB. Fits in A800 shared memory.
__shared__ float s_q_nope[NUM_QO_HEADS][HEAD_DIM_CKV];
__shared__ float s_q_pe[NUM_QO_HEADS][HEAD_DIM_KPE];
__shared__ float s_kc[HEAD_DIM_CKV];
__shared__ float s_kp[HEAD_DIM_KPE];

__global__ void mla_paged_decode_kernel(
    const void* __restrict__ q_nope,
    const void* __restrict__ q_pe,
    const void* __restrict__ ckv_cache,
    const void* __restrict__ kpe_cache,
    const int* __restrict__ kv_indptr,
    const int* __restrict__ kv_indices,
    void* __restrict__ output,
    float* __restrict__ lse,
    float sm_scale,
    int batch_size,
    int num_qo_heads,
    int head_dim_ckv,
    int head_dim_kpe
) {
    int b = blockIdx.x;
    int tid = threadIdx.x;
    int h = tid / THREADS_PER_HEAD;  // Which head this thread works on
    int t_in_head = tid % THREADS_PER_HEAD;  // Which thread within the head

    // Validate batch index
    if (b >= batch_size) return;

    // Get sequence range for this batch item
    int page_beg = kv_indptr[b];
    int page_end = kv_indptr[b + 1];
    int seq_len = page_end - page_beg;

    // Cast pointers to bfloat16
    const __nv_bfloat16* q_nope_bf16 = reinterpret_cast<const __nv_bfloat16*>(q_nope);
    const __nv_bfloat16* q_pe_bf16 = reinterpret_cast<const __nv_bfloat16*>(q_pe);
    const __nv_bfloat16* ckv_cache_bf16 = reinterpret_cast<const __nv_bfloat16*>(ckv_cache);
    const __nv_bfloat16* kpe_cache_bf16 = reinterpret_cast<const __nv_bfloat16*>(kpe_cache);
    __nv_bfloat16* output_bf16 = reinterpret_cast<__nv_bfloat16*>(output);

    if (seq_len <= 0) {
        // Zero out output and set lse to -inf
        for (int i = t_in_head; i < head_dim_ckv; i += THREADS_PER_HEAD) {
            output_bf16[b * num_qo_heads * head_dim_ckv + h * head_dim_ckv + i] = __float2bfloat16(0.0f);
        }
        lse[b * num_qo_heads + h] = -INFINITY;
        return;
    }

    // Load Q_nope and Q_pe into shared memory (once per batch item)
    // Each thread loads its portion of the head data
    {
        // Load Q_nope - coalesced access across threads
        const __nv_bfloat16* q_ptr = q_nope_bf16 + b * num_qo_heads * head_dim_ckv + h * head_dim_ckv;
        for (int i = t_in_head; i < head_dim_ckv; i += THREADS_PER_HEAD) {
            s_q_nope[h][i] = __bfloat162float(q_ptr[i]);
        }

        // Load Q_pe - coalesced access
        const __nv_bfloat16* q_pe_data_ptr = q_pe_bf16 + b * num_qo_heads * head_dim_kpe + h * head_dim_kpe;
        for (int i = t_in_head; i < head_dim_kpe; i += THREADS_PER_HEAD) {
            s_q_pe[h][i] = __bfloat162float(q_pe_data_ptr[i]);
        }
        __syncthreads();
    }

    // Initialize online softmax accumulators (per head)
    float m = -INFINITY;
    float d = 0.0f;

    // Register-based output accumulation - each thread accumulates partial results
    float output_vec[HEAD_DIM_CKV];
    for (int j = 0; j < HEAD_DIM_CKV; ++j) {
        output_vec[j] = 0.0f;
    }

    // Loop over sequence tokens
    for (int i = 0; i < seq_len; ++i) {
        int page_idx = kv_indices[page_beg + i];

        // Load Kc and Kp into shared memory
        // Coalesced load: 128 threads load 512 elements (4 each) for better bandwidth utilization
        const __nv_bfloat16* kc_ptr = ckv_cache_bf16 + page_idx * PAGE_SIZE * head_dim_ckv;
        const __nv_bfloat16* kp_ptr = kpe_cache_bf16 + page_idx * PAGE_SIZE * head_dim_kpe;

        // Load Kc with coalesced access
        for (int j = threadIdx.x; j < head_dim_ckv; j += THREADS_PER_BLOCK) {
            s_kc[j] = __bfloat162float(kc_ptr[j]);
        }

        // Load Kp with coalesced access
        for (int j = threadIdx.x; j < head_dim_kpe; j += THREADS_PER_BLOCK) {
            s_kp[j] = __bfloat162float(kp_ptr[j]);
        }
        __syncthreads();

        // Compute logits for this head
        float logit = 0.0f;

        // Dot product Q_nope @ Kc - parallelized across threads in head
        for (int j = t_in_head; j < head_dim_ckv; j += THREADS_PER_HEAD) {
            logit += s_q_nope[h][j] * s_kc[j];
        }

        // Dot product Q_pe @ Kp - parallelized across threads in head
        for (int j = t_in_head; j < head_dim_kpe; j += THREADS_PER_HEAD) {
            logit += s_q_pe[h][j] * s_kp[j];
        }

        // Warp-level reduction within head threads (8 threads per head)
        for (int offset = THREADS_PER_HEAD / 2; offset > 0; offset /= 2) {
            logit += __shfl_down_sync(0xffffffff, logit, offset);
        }

        // Only thread 0 in each head continues with softmax
        if (t_in_head == 0) {
            float logit_scaled = logit * sm_scale;

            // Online Softmax Update
            float m_new = fmaxf(m, logit_scaled);
            float alpha = expf(m - m_new);
            d = d * alpha + expf(logit_scaled - m_new);

            // Update output accumulation
            float exp_val = expf(logit_scaled - m_new);
            for (int j = 0; j < HEAD_DIM_CKV; ++j) {
                output_vec[j] = output_vec[j] * alpha + exp_val * s_kc[j];
            }

            m = m_new;
        }
        __syncthreads();
    }

    // Finalize output - handle d = 0 case to avoid division by zero
    // Only thread 0 in each head writes output
    if (t_in_head == 0) {
        if (d > 0.0f) {
            float scale = 1.0f / d;
            for (int j = 0; j < HEAD_DIM_CKV; ++j) {
                output_bf16[b * num_qo_heads * head_dim_ckv + h * head_dim_ckv + j] = __float2bfloat16(output_vec[j] * scale);
            }

            // Compute LSE (base 2)
            // logsumexp(x) = m + log(d)
            // lse = logsumexp / log(2)
            float log_d = logf(d);
            lse[b * num_qo_heads + h] = (m + log_d) * LOG2_E;
        } else {
            // No valid tokens, set output to 0 and LSE to -inf
            for (int j = 0; j < HEAD_DIM_CKV; ++j) {
                output_bf16[b * num_qo_heads * head_dim_ckv + h * head_dim_ckv + j] = __float2bfloat16(0.0f);
            }
            lse[b * num_qo_heads + h] = -INFINITY;
        }
    }
}

void run_mla_paged_decode(
    torch::Tensor q_nope,
    torch::Tensor q_pe,
    torch::Tensor ckv_cache,
    torch::Tensor kpe_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    torch::Tensor output,
    torch::Tensor lse,
    float sm_scale,
    int batch_size,
    int num_pages
) {
    // Launch configuration: 1 block per batch item, 128 threads per block
    // 8 threads per head for better parallelism and occupancy on A800
    dim3 grid(batch_size);
    dim3 block(THREADS_PER_BLOCK);

    mla_paged_decode_kernel<<<grid, block>>>(
        q_nope.data_ptr(),
        q_pe.data_ptr(),
        ckv_cache.data_ptr(),
        kpe_cache.data_ptr(),
        kv_indptr.data_ptr<int>(),
        kv_indices.data_ptr<int>(),
        output.data_ptr(),
        lse.data_ptr<float>(),
        sm_scale,
        batch_size,
        NUM_QO_HEADS,
        HEAD_DIM_CKV,
        HEAD_DIM_KPE
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <limits>
#include <string>
#include <cmath>
#include "kernel.h"

// Helper to check tensor properties
void check_tensor(const torch::Tensor& t, const std::string& name, torch::DeviceType device_type, torch::ScalarType dtype, int64_t expected_dim = -1) {
    TORCH_CHECK(t.device().type() == device_type, name, " must be on CUDA device");
    TORCH_CHECK(t.dtype() == dtype, name, " must be of dtype ", dtype);
    if (expected_dim != -1) {
        TORCH_CHECK(t.dim() == expected_dim, name, " must have ", expected_dim, " dimensions");
    }
}

std::vector<torch::Tensor> run(
    torch::Tensor q_nope,
    torch::Tensor q_pe,
    torch::Tensor ckv_cache,
    torch::Tensor kpe_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_indices,
    float sm_scale,
    torch::Tensor output = torch::Tensor(),
    torch::Tensor lse = torch::Tensor()
) {
    // Validate inputs
    check_tensor(q_nope, "q_nope", at::kCUDA, at::kBFloat16, 3);
    check_tensor(q_pe, "q_pe", at::kCUDA, at::kBFloat16, 3);
    check_tensor(ckv_cache, "ckv_cache", at::kCUDA, at::kBFloat16, 3);
    check_tensor(kpe_cache, "kpe_cache", at::kCUDA, at::kBFloat16, 3);
    check_tensor(kv_indptr, "kv_indptr", at::kCUDA, at::kInt, 1);
    check_tensor(kv_indices, "kv_indices", at::kCUDA, at::kInt, 1);

    int batch_size = q_nope.size(0);
    int num_qo_heads = q_nope.size(1);
    int head_dim_ckv = q_nope.size(2);
    int head_dim_kpe = q_pe.size(2);
    int page_size = ckv_cache.size(1);
    int num_pages = ckv_cache.size(0);
    int len_indptr = kv_indptr.size(0);
    int num_kv_indices = kv_indices.size(0);

    // Check constants
    TORCH_CHECK(num_qo_heads == 16, "num_qo_heads must be 16");
    TORCH_CHECK(head_dim_ckv == 512, "head_dim_ckv must be 512");
    TORCH_CHECK(head_dim_kpe == 64, "head_dim_kpe must be 64");
    TORCH_CHECK(page_size == 1, "page_size must be 1");
    TORCH_CHECK(len_indptr == batch_size + 1, "len_indptr must be batch_size + 1");
    TORCH_CHECK(num_kv_indices == kv_indptr[-1].item<int>(), "num_kv_indices mismatch");

    // Create or use provided output tensors
    if (output.numel() == 0) {
        output = torch::zeros(
            {batch_size, num_qo_heads, head_dim_ckv},
            torch::TensorOptions().dtype(torch::kBFloat16).device(at::kCUDA)
        );
    } else {
        TORCH_CHECK(output.sizes() == torch::IntArrayRef({batch_size, num_qo_heads, head_dim_ckv}),
                    "output tensor shape mismatch");
        TORCH_CHECK(output.dtype() == torch::kBFloat16, "output tensor dtype mismatch");
        TORCH_CHECK(output.device().is_cuda(), "output tensor must be on CUDA");
    }

    if (lse.numel() == 0) {
        lse = torch::full(
            {batch_size, num_qo_heads},
            -std::numeric_limits<float>::infinity(),
            torch::TensorOptions().dtype(torch::kFloat32).device(at::kCUDA)
        );
    } else {
        TORCH_CHECK(lse.sizes() == torch::IntArrayRef({batch_size, num_qo_heads}),
                    "lse tensor shape mismatch");
        TORCH_CHECK(lse.dtype() == torch::kFloat32, "lse tensor dtype mismatch");
        TORCH_CHECK(lse.device().is_cuda(), "lse tensor must be on CUDA");
    }

    // Run kernel
    run_mla_paged_decode(
        q_nope, q_pe, ckv_cache, kpe_cache,
        kv_indptr, kv_indices,
        output, lse,
        sm_scale,
        batch_size,
        num_pages
    );

    // Synchronize to ensure completion and catch errors
    cudaDeviceSynchronize();

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "MLA Paged Decode Kernel Execution");
}
